+#[cfg_attr(not(debug_assertions), unsafe(no_mangle))]
+pub unsafe extern "C" fn getipv4sourcefilter(
+    s: c_int,
+    interface_: c_uint,
+    group: c_uint,
+    fmode: *mut c_uint,
+    numsrc: *mut c_uint,
+    slist: *mut c_void,
